  {
    "file": "src/Components/Web/src/Forms/DisplayName.cs",
    "line": 39,
    "severity": "high",
    "description": "Missing render optimization: The component always re-renders on SetParametersAsync without checking if the 'For' parameter has changed. This violates Blazor component conventions. The component should only re-render when 'For' actually changes. The _previousFieldAccessor field (line 20) was declared for this optimization but is never used.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/DisplayName.cs
+++ b/src/Components/Web/src/Forms/DisplayName.cs
@@ -35,12 +35,16 @@
     Task IComponent.SetParametersAsync(ParameterView parameters)
     {
         parameters.SetParameterProperties(this);

-        var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
-        _displayName = newDisplayName;
-        _renderHandle.Render(BuildRenderTree);
+        if (_previousFieldAccessor != For)
+        {
+            var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
+            _displayName = newDisplayName;
+            _previousFieldAccessor = For;
+            _renderHandle.Render(BuildRenderTree);
+        }

         return Task.CompletedTask;
     }
"
  },
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 88,
    "severity": "critical",
    "description": "Incomplete hot reload cache invalidation: The ClearCache() method clears _memberInfoCache but not _displayNameCache. When hot reload applies metadata updates and clears the member cache, the cached display names remain stale. This causes the component to display outdated display names even after attributes change during development.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -86,5 +86,6 @@
     private static void ClearCache()
     {
         _memberInfoCache.Clear();
+        _displayNameCache.Clear();
     }
"
  },
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 59,
    "severity": "high",
    "description": "Incorrect attribute precedence: The code checks DisplayNameAttribute before DisplayAttribute, but the XML documentation (line 12-13) specifies 'reading from DisplayAttribute or DisplayNameAttribute', indicating Display should be checked first. DisplayAttribute is the newer, more comprehensive attribute and should take precedence when both are present.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -56,17 +56,17 @@
     public static string GetDisplayName(MemberInfo member)
     {
         ArgumentNullException.ThrowIfNull(member);

         return _displayNameCache.GetOrAdd(member, static m =>
         {
-            var displayNameAttribute = m.GetCustomAttribute<DisplayNameAttribute>();
-            if (displayNameAttribute?.DisplayName is not null)
-            {
-                return displayNameAttribute.DisplayName;
-            }
-
             var displayAttribute = m.GetCustomAttribute<DisplayAttribute>();
             if (displayAttribute is not null)
             {
                 var name = displayAttribute.GetName();
                 if (name is not null)
                 {
                     return name;
                 }
             }

+            var displayNameAttribute = m.GetCustomAttribute<DisplayNameAttribute>();
+            if (displayNameAttribute?.DisplayName is not null)
+            {
+                return displayNameAttribute.DisplayName;
+            }
+
             return m.Name;
         });
     }
"
  }
]

